/* ================= FLASHCARDS DATA ================= */
const CARDS = [
// ---- D1 ----
{d:'d1', f:'Algoritmo', b:'Conjunto de instrucciones/pasos para resolver un problema.', f_en:'Algorithm', b_en:'A set of instructions/steps to solve a problem.'},
{d:'d1', f:'Modelo', b:'Resultado de entrenar un algoritmo con datos; es lo que quedó "aprendido" y se usa para predecir.', f_en:'Model', b_en:'The result of training an algorithm on data; it\'s the "learned" thing used to predict.'},
{d:'d1', f:'Inferencia', b:'Momento en que un modelo ya entrenado responde ante datos nuevos.', f_en:'Inference', b_en:'When an already-trained model responds to new data.'},
{d:'d1', f:'Endpoint (SageMaker)', b:'Punto donde se publica un modelo para que otras aplicaciones lo consuman.', f_en:'Endpoint (SageMaker)', b_en:'The point where a model is published so other applications can consume it.'},
{d:'d1', f:'Jerarquía: IA ⊃ ML ⊃ Deep Learning ⊃ GenAI ⊃ Agentic AI', b:'IA: sistemas que imitan capacidades humanas.\nML: aprende patrones de los datos sin programación explícita.\nDeep Learning: redes neuronales multicapa, más datos/cómputo, patrones complejos.\nGenAI: genera contenido nuevo (texto/imagen/audio).\nAgentic AI: GenAI que además actúa de forma autónoma (planifica, usa herramientas).', f_en:'Hierarchy: AI ⊃ ML ⊃ Deep Learning ⊃ GenAI ⊃ Agentic AI', b_en:'AI: systems that imitate human capabilities.\nML: learns patterns from data without explicit programming.\nDeep Learning: multi-layer neural networks, more data/compute, complex patterns.\nGenAI: generates new content (text/image/audio).\nAgentic AI: GenAI that also acts autonomously (plans, uses tools).'},
{d:'d1', f:'Transfer Learning', b:'Tomar un modelo ya entrenado en una tarea y adaptarlo a una tarea nueva relacionada, sin entrenar desde cero. Ahorra tiempo, datos y costo.', f_en:'Transfer Learning', b_en:'Taking a model already trained on one task and adapting it to a new, related task, without training from scratch. Saves time, data, and cost.'},
{d:'d1', f:'Aprendizaje supervisado vs no supervisado vs por refuerzo', b:'Supervisado: datos etiquetados (clasificación, regresión).\nNo supervisado: sin etiquetas, encuentra patrones (clustering, anomalías).\nPor refuerzo: ensayo y error con recompensas/castigos.', f_en:'Supervised vs unsupervised vs reinforcement learning', b_en:'Supervised: labeled data (classification, regression).\nUnsupervised: no labels, finds patterns (clustering, anomalies).\nReinforcement: trial and error with rewards/penalties.'},
{d:'d1', f:'Regresión lineal vs logística', b:'Lineal: ajusta una línea a datos numéricos → predice valores continuos.\nLogística: a pesar del nombre, se usa para clasificación (ej. spam/no spam); predice probabilidad 0-1.', f_en:'Linear vs logistic regression', b_en:'Linear: fits a line to numeric data → predicts continuous values.\nLogistic: despite the name, used for classification (e.g. spam/not spam); predicts a 0-1 probability.'},
{d:'d1', f:'K-means', b:'Algoritmo de clustering no supervisado: agrupa datos sin etiquetas previas.', f_en:'K-means', b_en:'Unsupervised clustering algorithm: groups data with no prior labels.'},
{d:'d1', f:'Interpretabilidad: árboles vs redes', b:'Árboles de decisión / Random Forest: interpretables, explican cada decisión con reglas → buenos cuando hay que justificar (crédito, auditoría).\nRedes neuronales profundas: más precisas en patrones complejos pero "caja negra", difíciles de explicar.', f_en:'Interpretability: trees vs networks', b_en:'Decision trees / Random Forest: interpretable, explain each decision with rules → good when you need to justify (credit, audit).\nDeep neural networks: more accurate on complex patterns but a "black box", hard to explain.'},
{d:'d1', f:'Overfitting vs Underfitting', b:'Overfitting: el modelo "memoriza" el training set y falla con datos nuevos → alta varianza. Soluciones: más datos, regularización, simplificar, data augmentation, early stopping.\nUnderfitting: modelo demasiado simple → alto sesgo. Solución: más complejidad/features, entrenar más.', f_en:'Overfitting vs Underfitting', b_en:'Overfitting: the model "memorizes" the training set and fails on new data → high variance. Fixes: more data, regularization, simplify, data augmentation, early stopping.\nUnderfitting: model too simple → high bias. Fix: more complexity/features, train longer.'},
{d:'d1', f:'Amazon SageMaker Debugger', b:'Monitorea el entrenamiento en tiempo real y avisa si hay overfitting/underfitting.', f_en:'Amazon SageMaker Debugger', b_en:'Monitors training in real time and warns about overfitting/underfitting.'},
{d:'d1', f:'Los 4 tipos de inferencia', b:'Batch: procesa muchos registros a la vez, sin respuesta inmediata (Batch Transform).\nTiempo real: baja latencia, tráfico constante (Lex, Personalize).\nAsíncrona: inputs grandes (hasta 1GB), encola y entrega al terminar.\nServerless: tráfico intermitente/impredecible, no paga por infra ociosa.', f_en:'The 4 types of inference', b_en:'Batch: processes many records at once, no immediate response (Batch Transform).\nReal-time: low latency, steady traffic (Lex, Personalize).\nAsynchronous: large inputs (up to 1GB), queues and delivers when done.\nServerless: intermittent/unpredictable traffic, no charge for idle infra.'},
{d:'d1', f:'Textract vs Comprehend', b:'Textract: extrae el texto DE un documento escaneado (OCR, qué dice).\nComprehend: entiende el SIGNIFICADO del texto (sentimiento, entidades, PII). A menudo se usan juntos: Textract → Comprehend.', f_en:'Textract vs Comprehend', b_en:'Textract: extracts the text FROM a scanned document (OCR, what it says).\nComprehend: understands the MEANING of the text (sentiment, entities, PII). Often used together: Textract → Comprehend.'},
{d:'d1', f:'¿Cuándo NO usar Machine Learning?', b:'Cuando se necesita exactitud absoluta/determinística, cuando ya existe una fórmula simple, o cuando la decisión pone en riesgo directo la vida de una persona sin supervisión humana.', f_en:'When NOT to use Machine Learning?', b_en:'When you need absolute/deterministic accuracy, when a simple formula already exists, or when the decision directly risks someone\'s life without human oversight.'},
{d:'d1', f:'Accuracy, Precision, Recall, F1 Score', b:'Accuracy: % total de predicciones correctas.\nPrecision: de lo que el modelo dijo "positivo", cuánto era realmente positivo (evita falsos positivos).\nRecall: de todos los positivos reales, cuántos detectó el modelo (evita falsos negativos).\nF1 Score: media armónica entre precision y recall, útil cuando hay desbalance de clases.', f_en:'Accuracy, Precision, Recall, F1 Score', b_en:'Accuracy: total % of correct predictions.\nPrecision: of what the model called "positive", how much really was (avoids false positives).\nRecall: of all real positives, how many the model caught (avoids false negatives).\nF1 Score: harmonic mean of precision and recall, useful with class imbalance.'},
{d:'d1', f:'Métricas de modelo vs métricas de negocio', b:'Métricas de modelo: accuracy, precision, recall, F1 (miden desempeño técnico).\nMétricas de negocio: costo por usuario, costos de desarrollo, feedback del cliente, ROI (miden si el modelo realmente aporta valor al negocio).', f_en:'Model metrics vs business metrics', b_en:'Model metrics: accuracy, precision, recall, F1 (measure technical performance).\nBusiness metrics: cost per user, development costs, customer feedback, ROI (measure whether the model actually delivers business value).'},
{d:'d1', f:'Fuentes de modelos fundacionales', b:'Modelos open source pre-entrenados (listos para usar/adaptar) vs. entrenar un modelo custom desde cero. La mayoría de casos de uso empresariales parten de modelos pre-entrenados por costo y tiempo.', f_en:'Sources of foundation models', b_en:'Pre-trained open source models (ready to use/adapt) vs. training a custom model from scratch. Most enterprise use cases start from pre-trained models for cost and time reasons.'},
{d:'d1', f:'Métodos para usar un modelo en producción', b:'API administrada (managed API, ej. Amazon Bedrock: AWS gestiona la infraestructura) vs. self-hosted API (tú despliegas y gestionas el modelo, ej. en SageMaker o EC2, más control pero más responsabilidad operativa).', f_en:'Methods to use a model in production', b_en:'Managed API (e.g. Amazon Bedrock: AWS manages the infrastructure) vs. self-hosted API (you deploy and manage the model, e.g. on SageMaker or EC2, more control but more operational responsibility).'},
{d:'d1', f:'Conceptos fundamentales de MLOps', b:'Experimentación estructurada, procesos repetibles, sistemas escalables, gestión de deuda técnica, alcanzar production readiness, monitoreo continuo del modelo, y re-entrenamiento periódico.', f_en:'Fundamental MLOps concepts', b_en:'Structured experimentation, repeatable processes, scalable systems, managing technical debt, achieving production readiness, continuous model monitoring, and periodic re-training.'},
{d:'d1', f:'Matriz de confusión', b:'Tabla TP/FP/TN/FN. Base de todas las métricas de clasificación; LA respuesta cuando piden "evaluar en detalle un clasificador".', f_en:'Confusion matrix', b_en:'TP/FP/TN/FN table. Foundation of all classification metrics; THE answer when asked to "evaluate a classifier in detail".'},
{d:'d1', f:'Métricas de regresión: MSE, RMSE, MAE, R², MAPE', b:'Para predecir valores numéricos continuos. MSE/RMSE penalizan errores grandes; MAE = error absoluto medio; R² = varianza explicada (0–1); MAPE = error porcentual. NUNCA se usan para clasificación (trampa nº1 del examen).', f_en:'Regression metrics: MSE, RMSE, MAE, R², MAPE', b_en:'For predicting continuous numeric values. MSE/RMSE penalize large errors; MAE = mean absolute error; R² = explained variance (0–1); MAPE = percentage error. NEVER used for classification (the exam\'s #1 trap).'},
{d:'d1', f:'Perplexity', b:'Mide qué tan bien un modelo de lenguaje predice el siguiente token (menor = mejor). Es ajuste del lenguaje, NO exactitud de una tarea (para eso: F1, ROUGE).', f_en:'Perplexity', b_en:'Measures how well a language model predicts the next token (lower = better). It\'s language fit, NOT task accuracy (for that: F1, ROUGE).'},
{d:'d1', f:'Hiperparámetros vs parámetros', b:'Hiperparámetros: se fijan ANTES de entrenar (learning rate, batch size, épocas). Parámetros: los pesos que el modelo aprende. El ajuste de hiperparámetros busca la mejor combinación (SageMaker Automatic Model Tuning lo automatiza).', f_en:'Hyperparameters vs parameters', b_en:'Hyperparameters: set BEFORE training (learning rate, batch size, epochs). Parameters: the weights the model learns. Hyperparameter tuning searches for the best combination (SageMaker Automatic Model Tuning automates it).'},
{d:'d1', f:'Época (epoch)', b:'Una pasada completa por todos los datos de entrenamiento. Más épocas → mejor ajuste hasta que empieza el overfitting. Es configuración de entrenamiento, NO una métrica de evaluación.', f_en:'Epoch', b_en:'One full pass over all the training data. More epochs → better fit until overfitting kicks in. It\'s a training setting, NOT an evaluation metric.'},
{d:'d1', f:'SageMaker Canvas vs Autopilot', b:'Canvas: construir modelos SIN código (interfaz visual, no programadores). Autopilot (AutoML): construye, entrena y ajusta hiperparámetros automáticamente.', f_en:'SageMaker Canvas vs Autopilot', b_en:'Canvas: build models with NO code (visual interface, non-programmers). Autopilot (AutoML): automatically builds, trains, and tunes hyperparameters.'},
{d:'d1', f:'SageMaker Ground Truth (y Plus)', b:'Etiquetado de datos con trabajadores humanos. Ground Truth Plus = servicio de etiquetado totalmente gestionado por AWS. Distinto de A2I, que revisa PREDICCIONES en vivo, no etiqueta datos de entrenamiento.', f_en:'SageMaker Ground Truth (and Plus)', b_en:'Data labeling with human workers. Ground Truth Plus = fully AWS-managed labeling service. Different from A2I, which reviews live PREDICTIONS rather than labeling training data.'},
{d:'d1', f:'SageMaker Model Registry', b:'Catálogo central para guardar, versionar y gestionar modelos y su estado de despliegue. "Un solo lugar para todos los modelos" → Model Registry.', f_en:'SageMaker Model Registry', b_en:'Central catalog to store, version, and manage models and their deployment status. "One place for all models" → Model Registry.'},
{d:'d1', f:'k-NN vs K-means', b:'k-NN: clasificación SUPERVISADA por vecinos más cercanos (ej. clasificar flores por medidas). K-means: clustering NO supervisado. Nombres parecidos, tipos opuestos — trampa clásica.', f_en:'k-NN vs K-means', b_en:'k-NN: SUPERVISED classification by nearest neighbors (e.g. classifying flowers by measurements). K-means: UNsupervised clustering. Similar names, opposite types — a classic trap.'},
{d:'d1', f:'Semisupervisado / autosupervisado / federado', b:'Semisupervisado: pocos datos etiquetados + muchos sin etiquetar. Autosupervisado: el modelo genera sus propias etiquetas (pre-entrenamiento de LLMs). Federado: entrena sin mover los datos crudos → privacidad.', f_en:'Semi-supervised / self-supervised / federated', b_en:'Semi-supervised: little labeled data + lots of unlabeled. Self-supervised: the model generates its own labels (LLM pre-training). Federated: trains without moving raw data → privacy.'},
{d:'d1', f:'Autoencoders', b:'No supervisados: aprenden a reconstruir la entrada. Error de reconstrucción alto = anomalía. Respuesta típica para detectar anomalías SIN etiquetas.', f_en:'Autoencoders', b_en:'Unsupervised: they learn to reconstruct the input. High reconstruction error = anomaly. The typical answer for anomaly detection WITHOUT labels.'},
{d:'d1', f:'ARIMA / DeepAR', b:'Algoritmos de pronóstico de series de tiempo. DeepAR es el integrado de SageMaker y requiere datos de series de tiempo (valores indexados por fecha).', f_en:'ARIMA / DeepAR', b_en:'Time-series forecasting algorithms. DeepAR is SageMaker\'s built-in one and requires time-series data (values indexed by date).'},
{d:'d1', f:'Glue / Athena / QuickSight (Quick)', b:'Glue: ETL e integración de datos (DataBrew: preparación visual sin código). Athena: SQL serverless sobre S3. QuickSight/Amazon Quick: BI con preguntas en lenguaje natural y gráficos automáticos.', f_en:'Glue / Athena / QuickSight (Quick)', b_en:'Glue: ETL and data integration (DataBrew: visual no-code prep). Athena: serverless SQL on S3. QuickSight/Amazon Quick: BI with natural-language questions and automatic charts.'},
// ---- D2 ----
{d:'d2', f:'Token', b:'Pedazo de texto; puede ser una palabra completa o solo una parte de ella.', f_en:'Token', b_en:'A piece of text; can be a whole word or just part of one.'},
{d:'d2', f:'Chunking', b:'Dividir un texto largo en fragmentos más pequeños.', f_en:'Chunking', b_en:'Splitting a long text into smaller pieces.'},
{d:'d2', f:'Embeddings / vectores', b:'Lista de números que representa el significado de un dato. Permiten comparar significados en vez de palabras exactas (búsqueda semántica).', f_en:'Embeddings / vectors', b_en:'A list of numbers representing the meaning of a piece of data. They let you compare meanings instead of exact words (semantic search).'},
{d:'d2', f:'Transformer', b:'Arquitectura que permite a los modelos usar el contexto para identificar qué información es relevante.', f_en:'Transformer', b_en:'The architecture that lets models use context to identify which information is relevant.'},
{d:'d2', f:'Modelo fundacional (Foundation Model)', b:'Modelo base entrenado a gran escala, adaptable a múltiples tareas.', f_en:'Foundation Model', b_en:'A base model trained at large scale, adaptable to multiple tasks.'},
{d:'d2', f:'Modelos multimodales', b:'Entienden más de un tipo de dato en el mismo contexto (ej. texto + imagen).', f_en:'Multimodal models', b_en:'Understand more than one data type in the same context (e.g. text + image).'},
{d:'d2', f:'Modelos de difusión (Diffusion)', b:'Especializados en generar imágenes; parten de ruido aleatorio y lo "limpian" hasta formar la imagen (Stable Diffusion, Titan Image Generator).', f_en:'Diffusion models', b_en:'Specialized in generating images; they start from random noise and "clean it up" until the image forms (Stable Diffusion, Titan Image Generator).'},
{d:'d2', f:'GANs', b:'Generative Adversarial Networks: dos redes (generador vs discriminador) compiten para producir datos realistas.', f_en:'GANs', b_en:'Generative Adversarial Networks: two networks (generator vs discriminator) compete to produce realistic data.'},
{d:'d2', f:'Componentes de un buen prompt', b:'Rol, contexto, tarea específica, formato de salida.', f_en:'Components of a good prompt', b_en:'Role, context, specific task, output format.'},
{d:'d2', f:'Ciclo de vida de un modelo GenAI', b:'Selección de datos → selección del modelo → pre-training → fine-tuning → evaluación → despliegue → feedback (retroalimenta el ciclo, por eso es iterativo).', f_en:'Lifecycle of a GenAI model', b_en:'Data selection → model selection → pre-training → fine-tuning → evaluation → deployment → feedback (loops back into the cycle, that\'s why it\'s iterative).'},
{d:'d2', f:'Riesgos/límites de la GenAI', b:'Alucinaciones, no determinismo (respuestas distintas al mismo input), inexactitud por datos de entrenamiento, interpretabilidad limitada.', f_en:'Risks/limits of GenAI', b_en:'Hallucinations, nondeterminism (different answers to the same input), inaccuracy from training data, limited interpretability.'},
{d:'d2', f:'Amazon Bedrock', b:'Servicio principal de GenAI en AWS. Acceso a modelos de varios proveedores (Claude, Llama, Stability AI) vía API unificada, sin gestionar servidores, pago por token.', f_en:'Amazon Bedrock', b_en:'AWS\'s main GenAI service. Access to models from multiple providers (Claude, Llama, Stability AI) via a unified API, no server management, pay per token.'},
{d:'d2', f:'Amazon Q', b:'Asistente experto de AWS: Q Business (responde sobre documentos de la empresa) y Q Developer (ayuda con código y tareas de AWS).', f_en:'Amazon Q', b_en:'AWS\'s expert assistant: Q Business (answers about company documents) and Q Developer (helps with code and AWS tasks).'},
{d:'d2', f:'SageMaker JumpStart', b:'Catálogo de modelos pre-entrenados para perfiles técnicos que quieren más control sobre entrenamiento y despliegue.', f_en:'SageMaker JumpStart', b_en:'A catalog of pre-trained models for technical users who want more control over training and deployment.'},
{d:'d2', f:'PartyRock', b:'"Patio de juegos" basado en Bedrock para crear apps de IA sin programar — ideal para prototipos rápidos, "sin código".', f_en:'PartyRock', b_en:'A Bedrock-based "playground" for building AI apps without coding — ideal for fast, "no-code" prototypes.'},
{d:'d2', f:'¿Cómo elegir el modelo correcto?', b:'Tipo de modelo (texto/imagen/multimodal), rendimiento/latencia, restricciones (datos sensibles), cumplimiento normativo, costo (se cobra por token).', f_en:'How to choose the right model?', b_en:'Model type (text/image/multimodal), performance/latency, constraints (sensitive data), regulatory compliance, cost (billed per token).'},
{d:'d2', f:'Métricas de éxito de negocio en GenAI', b:'Eficiencia, tasa de conversión, customer lifetime value, exactitud. Las métricas de NEGOCIO son las que justifican el proyecto.', f_en:'Business success metrics in GenAI', b_en:'Efficiency, conversion rate, customer lifetime value, accuracy. BUSINESS metrics are what justify the project.'},
{d:'d2', f:'Context Engineering', b:'Disciplina más amplia que el prompt engineering: diseñar y gestionar TODO el contexto que recibe el modelo (historial, documentos recuperados, herramientas disponibles, memoria), no solo el texto del prompt individual.', f_en:'Context Engineering', b_en:'A broader discipline than prompt engineering: designing and managing ALL the context the model receives (history, retrieved documents, available tools, memory), not just the individual prompt text.'},
{d:'d2', f:'Patrones de IA agéntica (multi-agente)', b:'Multi-agent system patterns: varios agentes especializados colaborando.\nMemory management: cómo el agente recuerda contexto entre pasos/sesiones.\nTool usage: cómo decide qué herramienta invocar.\nWorkflow orchestration: cómo se coordinan los pasos de principio a fin.\nComunicación multi-agente: cómo los agentes se pasan información entre sí (ej. protocolo A2A).', f_en:'Agentic AI patterns (multi-agent)', b_en:'Multi-agent system patterns: several specialized agents collaborating.\nMemory management: how the agent remembers context across steps/sessions.\nTool usage: how it decides which tool to invoke.\nWorkflow orchestration: how steps are coordinated end to end.\nMulti-agent communication: how agents pass information to each other (e.g. A2A protocol).'},
{d:'d2', f:'Amazon Bedrock AgentCore', b:'Plataforma de AWS (2026) para desplegar y operar agentes de IA en producción a escala empresarial: runtime serverless, gestión de memoria, identidad/seguridad, gateway para conectar herramientas, y observabilidad. Funciona con cualquier framework (LangGraph, CrewAI, Strands) y cualquier modelo.', f_en:'Amazon Bedrock AgentCore', b_en:'AWS\'s (2026) platform for deploying and running AI agents in production at enterprise scale: serverless runtime, memory management, identity/security, a tool-connection gateway, and observability. Works with any framework (LangGraph, CrewAI, Strands) and any model.'},
{d:'d2', f:'Strands Agents', b:'Framework open source de AWS para construir y orquestar agentes de IA (single-agent hasta sistemas multi-agente complejos) con pocas líneas de código. Se integra de forma nativa con Amazon Bedrock AgentCore.', f_en:'Strands Agents', b_en:'AWS\'s open source framework for building and orchestrating AI agents (single-agent up to complex multi-agent systems) with just a few lines of code. Integrates natively with Amazon Bedrock AgentCore.'},
{d:'d2', f:'Amazon Quick', b:'Evolución de Amazon Q Business (2026): asistente de IA agéntico para trabajo de oficina que no solo responde preguntas sino que ejecuta acciones/flujos de varios pasos, conectando datos de toda la empresa (documentos, apps, bases de datos).', f_en:'Amazon Quick', b_en:'The evolution of Amazon Q Business (2026): an agentic AI assistant for office work that doesn\'t just answer questions but executes multi-step actions/workflows, connecting data across the whole company (documents, apps, databases).'},
{d:'d2', f:'Kiro', b:'IDE agéntico de AWS para desarrollo de software basado en "spec-driven development": convierte requisitos en especificaciones y luego en código funcional, pruebas y documentación. Sustituye a Amazon Q Developer como asistente de código de AWS.', f_en:'Kiro', b_en:'AWS\'s agentic IDE for software development based on "spec-driven development": turns requirements into specs and then into working code, tests, and documentation. Replaces Amazon Q Developer as AWS\'s code assistant.'},
{d:'d2', f:'Bedrock: On-Demand vs Provisioned Throughput', b:'On-Demand: pago por token, sin compromiso → prototipos y tráfico impredecible. Provisioned Throughput: capacidad reservada → tráfico alto y constante, y es OBLIGATORIO para servir modelos personalizados (fine-tuned) en Bedrock.', f_en:'Bedrock: On-Demand vs Provisioned Throughput', b_en:'On-Demand: pay per token, no commitment → prototypes and unpredictable traffic. Provisioned Throughput: reserved capacity → high steady traffic, and it is REQUIRED to serve custom (fine-tuned) models on Bedrock.'},
{d:'d2', f:'¿Qué determina el costo de inferencia de un LLM?', b:'Los tokens de entrada + salida procesados. Prompts más cortos, menos ejemplos few-shot y menor límite de salida = menos costo. Temperature/top-k/top-p NO afectan el costo. El historial de conversación en cada prompt hace crecer los tokens.', f_en:'What drives LLM inference cost?', b_en:'The input + output tokens processed. Shorter prompts, fewer few-shot examples, and a lower output limit = lower cost. Temperature/top-k/top-p do NOT affect cost. Conversation history in each prompt makes tokens grow.'},
{d:'d2', f:'Trainium vs Inferentia', b:'Chips de AWS: Trainium (instancias Trn) = ENTRENAMIENTO eficiente en energía → menor impacto ambiental. Inferentia (instancias Inf) = INFERENCIA de bajo costo/consumo. P y G = GPUs de propósito general.', f_en:'Trainium vs Inferentia', b_en:'AWS chips: Trainium (Trn instances) = energy-efficient TRAINING → lowest environmental impact. Inferentia (Inf instances) = low-cost, low-power INFERENCE. P and G = general-purpose GPUs.'},
{d:'d2', f:'Amazon Nova (familia de FMs de Amazon)', b:'Micro/Lite/Pro: texto y multimodal (Lite = multimodal multilenguaje económico). Nova Canvas: genera IMÁGENES. Nova Reel: genera VIDEO. Titan es la familia anterior de Amazon.', f_en:'Amazon Nova (Amazon\'s FM family)', b_en:'Micro/Lite/Pro: text and multimodal (Lite = low-cost multilingual multimodal). Nova Canvas: generates IMAGES. Nova Reel: generates VIDEO. Titan is Amazon\'s previous family.'},
{d:'d2', f:'HealthScribe / Comprehend Medical / AWS Transform', b:'HealthScribe: voz→texto + GenAI para notas clínicas de consultas. Comprehend Medical: extrae entidades clínicas de texto médico. AWS Transform: moderniza aplicaciones legadas con IA agéntica.', f_en:'HealthScribe / Comprehend Medical / AWS Transform', b_en:'HealthScribe: speech-to-text + GenAI for clinical notes from visits. Comprehend Medical: extracts clinical entities from medical text. AWS Transform: modernizes legacy applications with agentic AI.'},
// ---- D3 ----
{d:'d3', f:'El "trilema" al elegir un modelo fundacional', b:'Costo vs Latencia vs Calidad/soporte multilenguaje — siempre hay que balancear los tres.', f_en:'The "trilemma" of choosing a foundation model', b_en:'Cost vs Latency vs Quality/multilingual support — you always have to balance the three.'},
{d:'d3', f:'Ventana de contexto', b:'Cantidad máxima de tokens (input + output) que el modelo puede "ver" en una sola interacción.', f_en:'Context window', b_en:'The maximum number of tokens (input + output) the model can "see" in a single interaction.'},
{d:'d3', f:'Prompt caching', b:'Guarda en memoria el procesamiento de partes repetidas de un prompt; reduce latencia y costo en llamadas repetidas.', f_en:'Prompt caching', b_en:'Stores the processing of repeated prompt parts in memory; reduces latency and cost on repeated calls.'},
{d:'d3', f:'Temperature', b:'Controla la distribución de probabilidad al elegir el siguiente token. Baja → respuestas consistentes/deterministas. 0.7–1 → más creatividad.', f_en:'Temperature', b_en:'Controls the probability distribution when picking the next token. Low → consistent/deterministic answers. 0.7–1 → more creativity.'},
{d:'d3', f:'Top-K vs Top-P', b:'Top-K: restringe a los K tokens más probables (número FIJO).\nTop-P (nucleus sampling): elige dinámicamente el conjunto mínimo cuya probabilidad acumulada suma ≥ P (número VARIABLE).', f_en:'Top-K vs Top-P', b_en:'Top-K: restricts to the K most likely tokens (a FIXED number).\nTop-P (nucleus sampling): dynamically picks the smallest set whose cumulative probability sums to ≥ P (a VARIABLE number).'},
{d:'d3', f:'Max tokens y Stop sequences', b:'Max tokens: limita la longitud de la respuesta.\nStop sequences: secuencias que, al aparecer, detienen la generación.', f_en:'Max tokens and Stop sequences', b_en:'Max tokens: limits the length of the response.\nStop sequences: sequences that, when they appear, stop generation.'},
{d:'d3', f:'¿Los parámetros de inferencia afectan el costo?', b:'No: temperature, top-k y top-p NO afectan precio ni latencia, solo la aleatoriedad/creatividad. El precio depende de la cantidad de tokens.', f_en:'Do inference parameters affect cost?', b_en:'No: temperature, top-k, and top-p do NOT affect price or latency, only randomness/creativity. Price depends on the number of tokens.'},
{d:'d3', f:'RAG (Retrieval-Augmented Generation)', b:'El modelo recupera información relevante de una fuente externa antes de responder. En AWS: Amazon Bedrock Knowledge Bases orquesta el flujo. Ideal para datos que cambian frecuentemente o documentos privados.', f_en:'RAG (Retrieval-Augmented Generation)', b_en:'The model retrieves relevant information from an external source before responding. On AWS: Amazon Bedrock Knowledge Bases orchestrates the flow. Ideal for data that changes often or private documents.'},
{d:'d3', f:'RAG vs Fine-tuning', b:'RAG = añadir conocimiento externo/actualizable sin reentrenar (consulta datos al momento).\nFine-tuning = cambiar el comportamiento/estilo reentrenando los pesos.\n"Datos que cambian" → RAG · "tono/formato/dominio especializado" → fine-tuning.', f_en:'RAG vs Fine-tuning', b_en:'RAG = adds external/updatable knowledge without retraining (queries data on the fly).\nFine-tuning = changes behavior/style by retraining the weights.\n"Data that changes" → RAG · "specialized tone/format/domain" → fine-tuning.'},
{d:'d3', f:'Bases de datos vectoriales en AWS', b:'OpenSearch Service: búsqueda vectorial a gran escala/alta concurrencia.\nAurora/RDS PostgreSQL + pgvector: ya usas SQL y quieres simplicidad.\nNeptune: modelar relaciones entre documentos (grafos).\nDocumentDB: datos en formato JSON, compatible con MongoDB.', f_en:'Vector databases on AWS', b_en:'OpenSearch Service: vector search at large scale/high concurrency.\nAurora/RDS PostgreSQL + pgvector: you already use SQL and want simplicity.\nNeptune: model relationships between documents (graphs).\nDocumentDB: JSON-format data, MongoDB-compatible.'},
{d:'d3', f:'Agentes y MCP', b:'Un agente completa tareas multi-paso usando herramientas externas, decidiendo qué usar y en qué orden. Agents for Bedrock: implementación de AWS. MCP: estándar abierto para conectar agentes con herramientas externas, reduce el esfuerzo de integración.', f_en:'Agents and MCP', b_en:'An agent completes multi-step tasks using external tools, deciding what to use and in what order. Agents for Bedrock: AWS\'s implementation. MCP: an open standard for connecting agents to external tools, reduces integration effort.'},
{d:'d3', f:'Trade-offs de personalización del modelo', b:'Pre-training: desde cero, control absoluto, costo extremo.\nFine-tuning: ajusta pesos con datos específicos, costo moderado.\nIn-Context Learning: ejemplos en el prompt, sin tocar pesos, bajo costo.\nPrompt engineering: el más económico y rápido.', f_en:'Model customization trade-offs', b_en:'Pre-training: from scratch, absolute control, extreme cost.\nFine-tuning: adjusts weights with specific data, moderate cost.\nIn-Context Learning: examples in the prompt, no weight changes, low cost.\nPrompt engineering: the cheapest and fastest.'},
{d:'d3', f:'Negative prompt / Latent space / Prompt routing', b:'Negative prompt: indica qué NO debe hacer/incluir el modelo.\nLatent space: espacio matemático donde el modelo "guarda" lo aprendido.\nPrompt routing: capa que dirige la solicitud al modelo/flujo más adecuado.', f_en:'Negative prompt / Latent space / Prompt routing', b_en:'Negative prompt: states what the model should NOT do/include.\nLatent space: the mathematical space where the model "stores" what it has learned.\nPrompt routing: a layer that routes the request to the most suitable model/flow.'},
{d:'d3', f:'Tipos de prompting', b:'Zero-shot: sin ejemplos.\nSingle-shot: un ejemplo.\nFew-shot: 2-5 ejemplos.\nChain-of-thought: pide razonamiento paso a paso.\nPrompt templates: estructuras reutilizables.', f_en:'Types of prompting', b_en:'Zero-shot: no examples.\nSingle-shot: one example.\nFew-shot: 2-5 examples.\nChain-of-thought: asks for step-by-step reasoning.\nPrompt templates: reusable structures.'},
{d:'d3', f:'Riesgos de los prompts', b:'Exposure: se filtran instrucciones confidenciales del prompt (mitiga: Bedrock Guardrails).\nPoisoning: ataque al entrenamiento.\nHijacking: instrucciones maliciosas inyectadas en el prompt.\nJailbreaking: evadir las restricciones de seguridad del modelo.', f_en:'Prompt risks', b_en:'Exposure: confidential prompt instructions leak out (mitigated by: Bedrock Guardrails).\nPoisoning: an attack on training.\nHijacking: malicious instructions injected into the prompt.\nJailbreaking: evading the model\'s safety restrictions.'},
{d:'d3', f:'Distillation (destilación)', b:'Entrenar un modelo pequeño ("estudiante") para replicar el comportamiento de uno grande ("maestro"), con menor costo/latencia.', f_en:'Distillation', b_en:'Training a small model (the "student") to replicate the behavior of a large one (the "teacher"), at lower cost/latency.'},
{d:'d3', f:'Continuous pre-training', b:'Seguir entrenando un modelo existente con datos nuevos (sin partir de cero) para actualizarlo o especializarlo.', f_en:'Continuous pre-training', b_en:'Continuing to train an existing model on new data (without starting from scratch) to update or specialize it.'},
{d:'d3', f:'Amazon Bedrock Model Evaluation', b:'Herramienta integrada en Bedrock para ejecutar evaluaciones automáticas y con revisores humanos desde la consola, sin construir infraestructura propia.', f_en:'Amazon Bedrock Model Evaluation', b_en:'A tool built into Bedrock to run automatic and human-reviewer evaluations from the console, without building your own infrastructure.'},
{d:'d3', f:'Métricas automáticas: ROUGE / BLEU / BERTScore', b:'ROUGE → resúmenes (superposición con referencia humana; ROUGE-L: subsecuencia común más larga).\nBLEU → traducción (n-gramas vs referencia).\nBERTScore → equivalencia semántica vía embeddings.', f_en:'Automatic metrics: ROUGE / BLEU / BERTScore', b_en:'ROUGE → summarization (overlap with a human reference; ROUGE-L: longest common subsequence).\nBLEU → translation (n-grams vs. reference).\nBERTScore → semantic equivalence via embeddings.'},
{d:'d3', f:'Benchmark datasets', b:'Datasets estándar de la industria para medir capacidades del modelo de forma objetiva y reproducible (ej. MMLU, HumanEval).', f_en:'Benchmark datasets', b_en:'Industry-standard datasets for measuring model capabilities objectively and reproducibly (e.g. MMLU, HumanEval).'},
{d:'d3', f:'Buenas prácticas de prompt engineering', b:'Mejorar la calidad de respuesta iterando, experimentar activamente, usar guardrails, ser específico y conciso, y estructurar prompts complejos con múltiples instrucciones/comentarios claros.', f_en:'Prompt engineering best practices', b_en:'Improving response quality by iterating, actively experimenting, using guardrails, being specific and concise, and structuring complex prompts with clear multiple instructions/comments.'},
{d:'d3', f:'Amazon Bedrock Prompt Management', b:'Funcionalidad de Bedrock para versionar y gestionar prompts de forma centralizada (crear versiones, probarlas, desplegarlas), evitando prompts "sueltos" y no controlados en el código.', f_en:'Amazon Bedrock Prompt Management', b_en:'A Bedrock feature for versioning and managing prompts centrally (create versions, test them, deploy them), avoiding "loose", uncontrolled prompts in code.'},
{d:'d3', f:'RLHF (Reinforcement Learning from Human Feedback)', b:'Técnica de fine-tuning donde humanos califican las respuestas del modelo y esa retroalimentación se usa como señal de recompensa para ajustar el modelo hacia respuestas más alineadas con las preferencias humanas.', f_en:'RLHF (Reinforcement Learning from Human Feedback)', b_en:'A fine-tuning technique where humans rate the model\'s responses and that feedback is used as a reward signal to adjust the model toward responses more aligned with human preferences.'},
{d:'d3', f:'Instruction tuning', b:'Tipo de fine-tuning donde el modelo se entrena con ejemplos de instrucción→respuesta deseada, para que siga mejor instrucciones explícitas en lenguaje natural.', f_en:'Instruction tuning', b_en:'A type of fine-tuning where the model is trained on instruction→desired-response examples, so it follows explicit natural-language instructions better.'},
{d:'d3', f:'LLM-as-a-judge', b:'Método de evaluación donde se usa OTRO modelo de lenguaje (más grande o especializado) para calificar/comparar las respuestas de un modelo evaluado, en vez de depender solo de evaluadores humanos.', f_en:'LLM-as-a-judge', b_en:'An evaluation method that uses ANOTHER language model (larger or specialized) to score/compare the responses of an evaluated model, instead of relying only on human evaluators.'},
{d:'d3', f:'Evaluar aplicaciones construidas con FMs (RAG, agentes, workflows)', b:'No basta con evaluar el modelo aislado: hay que evaluar el sistema completo (ej. si el RAG recupera los documentos correctos, si el agente ejecuta la secuencia de pasos correcta).', f_en:'Evaluating applications built with FMs (RAG, agents, workflows)', b_en:'Evaluating the model in isolation isn\'t enough: you need to evaluate the whole system (e.g. whether RAG retrieves the right documents, whether the agent executes the right sequence of steps).'},
{d:'d3', f:'Métricas de alineación con objetivos de negocio', b:'Task completion rate (% de tareas completadas exitosamente), user satisfaction, cost per interaction — conectan el desempeño técnico del modelo con el valor real para el negocio.', f_en:'Metrics aligned with business goals', b_en:'Task completion rate (% of successfully completed tasks), user satisfaction, cost per interaction — these connect the model\'s technical performance to real business value.'},
{d:'d3', f:'Chain-of-thought vs Prompt chaining vs Tree of thoughts', b:'Chain-of-thought: razonamiento paso a paso DENTRO de una respuesta. Prompt chaining: subtareas enviadas en SECUENCIA, cada paso usa la salida del anterior. Tree of thoughts: explora VARIAS ramas de razonamiento en paralelo.', f_en:'Chain-of-thought vs Prompt chaining vs Tree of thoughts', b_en:'Chain-of-thought: step-by-step reasoning WITHIN one response. Prompt chaining: subtasks sent in SEQUENCE, each step uses the previous output. Tree of thoughts: explores SEVERAL reasoning branches in parallel.'},
{d:'d3', f:'ReAct (Reason + Act)', b:'Técnica de prompting que intercala razonamiento con acciones/llamadas a herramientas. LA respuesta cuando el modelo necesita consultar datos en vivo (ej. inventario por API) para responder.', f_en:'ReAct (Reason + Act)', b_en:'Prompting technique that interleaves reasoning with actions/tool calls. THE answer when the model needs live data (e.g. inventory via API) to respond.'},
{d:'d3', f:'Generación de imágenes: CFG scale / steps / seed', b:'CFG scale: qué tanto obedece la imagen al prompt (imágenes aleatorias → subir CFG). Steps: más pasos = más detalle. Seed: fija la semilla → resultados reproducibles. Negative prompt: qué NO debe aparecer.', f_en:'Image generation: CFG scale / steps / seed', b_en:'CFG scale: how closely the image follows the prompt (random images → raise CFG). Steps: more steps = more detail. Seed: fixing it → reproducible results. Negative prompt: what must NOT appear.'},
{d:'d3', f:'Adversarial prompting', b:'Probar el modelo deliberadamente con prompts hostiles para detectar y neutralizar intentos de inyección — la técnica de prompting para ENDURECER el modelo contra ataques.', f_en:'Adversarial prompting', b_en:'Deliberately testing the model with hostile prompts to detect and neutralize injection attempts — the prompting technique to HARDEN the model against attacks.'},
// ---- D4 ----
{d:'d4', f:'Bias, Fairness, Inclusivity', b:'Bias: trato desigual a grupos, viene de los datos.\nFairness: decisiones consistentes sin importar datos sensibles.\nInclusivity: funciona bien para todos los grupos (y tipos de dato).', f_en:'Bias, Fairness, Inclusivity', b_en:'Bias: unequal treatment of groups, comes from the data.\nFairness: consistent decisions regardless of sensitive data.\nInclusivity: works well for all groups (and data types).'},
{d:'d4', f:'Robustness, Safety, Veracity', b:'Robustness: sigue funcionando ante entradas inusuales.\nSafety: no causa daño ni pone en riesgo a personas.\nVeracity: es honesto, reconoce cuando no sabe algo.', f_en:'Robustness, Safety, Veracity', b_en:'Robustness: keeps working with unusual inputs.\nSafety: doesn\'t cause harm or put people at risk.\nVeracity: is honest, acknowledges when it doesn\'t know something.'},
{d:'d4', f:'Riesgos legales de la GenAI', b:'Infracción de propiedad intelectual (contenido similar a obras protegidas), salidas sesgadas (demandas por discriminación), riesgo al usuario final (alucinaciones en salud/finanzas → responsabilidad legal).', f_en:'Legal risks of GenAI', b_en:'Intellectual property infringement (content similar to protected works), biased outputs (discrimination lawsuits), end-user risk (hallucinations in healthcare/finance → legal liability).'},
{d:'d4', f:'Sesgo y varianza: causa y efecto', b:'Sesgo en los datos → errores sistemáticos (subrepresenta grupos).\nAlta varianza → overfitting.\nBajo varianza + alto sesgo → underfitting.', f_en:'Bias and variance: cause and effect', b_en:'Bias in the data → systematic errors (underrepresents groups).\nHigh variance → overfitting.\nLow variance + high bias → underfitting.'},
{d:'d4', f:'Amazon SageMaker Clarify', b:'Detecta sesgo (pre y post-entrenamiento) y explica predicciones con feature attribution (valores SHAP): cuánto pesa cada variable en una decisión.', f_en:'Amazon SageMaker Clarify', b_en:'Detects bias (pre- and post-training) and explains predictions via feature attribution (SHAP values): how much each variable matters in a decision.'},
{d:'d4', f:'SageMaker Model Monitor vs Clarify', b:'Model Monitor: vigila drift en PRODUCCIÓN (cuándo se degrada el modelo).\nClarify: sesgo + explicabilidad (el "por qué"). Se integran: Clarify detecta, Model Monitor alerta vía CloudWatch.', f_en:'SageMaker Model Monitor vs Clarify', b_en:'Model Monitor: watches for drift in PRODUCTION (when the model degrades).\nClarify: bias + explainability (the "why"). They combine: Clarify detects, Model Monitor alerts via CloudWatch.'},
{d:'d4', f:'Amazon Augmented AI (A2I)', b:'Cuando el modelo tiene baja confianza o el error es inaceptable, envía esos casos automáticamente a revisión humana.', f_en:'Amazon Augmented AI (A2I)', b_en:'When the model has low confidence or the error is unacceptable, it automatically routes those cases to human review.'},
{d:'d4', f:'Amazon Bedrock Guardrails', b:'Define los límites del comportamiento del modelo en tiempo real (filtros de contenido, temas denegados, protección de PII).', f_en:'Amazon Bedrock Guardrails', b_en:'Defines the model\'s behavior limits in real time (content filters, denied topics, PII protection).'},
{d:'d4', f:'Principios oficiales de IA Responsable de AWS', b:'Fairness, Explainability, Privacy & Security, Robustness, Governance, Transparency, Safety, Veracity & Controllability.', f_en:'AWS\'s official Responsible AI principles', b_en:'Fairness, Explainability, Privacy & Security, Robustness, Governance, Transparency, Safety, Veracity & Controllability.'},
{d:'d4', f:'Transparencia vs Explicabilidad', b:'Transparencia: puedes ver cómo está construido el modelo (arquitectura, datos, parámetros).\nExplicabilidad: además entiendes POR QUÉ tomó una decisión específica. "Caja negra" = ni transparencia ni explicabilidad. SageMaker Model Cards documenta ambas.', f_en:'Transparency vs Explainability', b_en:'Transparency: you can see how the model is built (architecture, data, parameters).\nExplainability: you also understand WHY it made a specific decision. "Black box" = neither transparency nor explainability. SageMaker Model Cards documents both.'},
{d:'d4', f:'Diseño centrado en el humano para IA explicable', b:'Incorporar mecanismos de feedback del usuario y priorizar la transparencia de las decisiones de la IA desde el diseño de la aplicación, no solo como una capa técnica añadida después.', f_en:'Human-centered design for explainable AI', b_en:'Building in user feedback mechanisms and prioritizing the transparency of AI decisions from the application\'s design stage, not just as a technical layer bolted on afterward.'},
{d:'d4', f:'Model Cards vs AI Service Cards', b:'SageMaker Model Cards: documentación estandarizada de TUS modelos (uso previsto, datos, métricas, limitaciones, versiones) para gobernanza y auditoría. AWS AI Service Cards: documentación de AWS sobre SUS PROPIOS servicios de IA.', f_en:'Model Cards vs AI Service Cards', b_en:'SageMaker Model Cards: standardized documentation of YOUR models (intended use, data, metrics, limitations, versions) for governance and audits. AWS AI Service Cards: AWS\'s documentation about ITS OWN AI services.'},
{d:'d4', f:'Watermark detection (Bedrock)', b:'Detecta la marca de agua invisible de imágenes generadas por modelos de Amazon → transparencia sobre qué contenido fue generado por IA. Es una función de seguridad/filtrado de Bedrock junto con Guardrails.', f_en:'Watermark detection (Bedrock)', b_en:'Detects the invisible watermark in images generated by Amazon models → transparency about which content was AI-generated. A Bedrock safety/filtering feature alongside Guardrails.'},
{d:'d4', f:'Sostenibilidad en IA', b:'Elegir un modelo del tamaño ADECUADO a la tarea (no el más grande) reduce cómputo, energía e impacto ambiental. Para entrenar con menor huella → instancias Trn (Trainium).', f_en:'Sustainability in AI', b_en:'Choosing a model SIZED for the task (not the biggest) reduces compute, energy, and environmental impact. For lower-footprint training → Trn (Trainium) instances.'},
{d:'d4', f:'Plagio y pérdida de confianza', b:'Plagio: presentar salida de IA como trabajo propio sin atribución. Pérdida de confianza del cliente: respuestas incorrectas → quejas, prensa negativa y escrutinio regulatorio. Ambos son riesgos legales/reputacionales de la GenAI.', f_en:'Plagiarism and loss of trust', b_en:'Plagiarism: presenting AI output as your own work without attribution. Loss of customer trust: incorrect answers → complaints, negative press, regulatory scrutiny. Both are legal/reputational GenAI risks.'},
// ---- D5 ----
{d:'d5', f:'AWS IAM, KMS, Macie, PrivateLink', b:'IAM: controla accesos (mínimo privilegio).\nKMS: crea/controla claves de cifrado y su rotación.\nMacie: usa ML para descubrir datos sensibles (PII) en S3.\nPrivateLink: conecta apps a servicios de AWS por red privada, sin salir a internet.', f_en:'AWS IAM, KMS, Macie, PrivateLink', b_en:'IAM: controls access (least privilege).\nKMS: creates/controls encryption keys and their rotation.\nMacie: uses ML to discover sensitive data (PII) in S3.\nPrivateLink: connects apps to AWS services over a private network, without going out to the internet.'},
{d:'d5', f:'Modelo de responsabilidad compartida', b:'AWS: seguridad DE la nube (infraestructura física, hardware, virtualización).\nCliente: seguridad EN la nube (configuración, datos, accesos, modelos, código).', f_en:'Shared responsibility model', b_en:'AWS: security OF the cloud (physical infrastructure, hardware, virtualization).\nCustomer: security IN the cloud (configuration, data, access, models, code).'},
{d:'d5', f:'Data lineage vs Data cataloging', b:'Data lineage: rastrea el origen y recorrido de los datos (para auditar decisiones incorrectas).\nData cataloging: inventario organizado de todos los datos de la empresa.', f_en:'Data lineage vs Data cataloging', b_en:'Data lineage: tracks the origin and path of data (to audit incorrect decisions).\nData cataloging: an organized inventory of all the company\'s data.'},
{d:'d5', f:'Prompt injection y otros ataques', b:'Prompt injection: instrucciones maliciosas vía el input del usuario (mitiga: Bedrock Guardrails).\nJailbreaking: evadir restricciones de seguridad.\nData poisoning: envenenar datos de entrenamiento.\nModel inversion/extraction: reconstruir datos de entrenamiento o el modelo a partir de sus salidas.', f_en:'Prompt injection and other attacks', b_en:'Prompt injection: malicious instructions via user input (mitigated by: Bedrock Guardrails).\nJailbreaking: evading safety restrictions.\nData poisoning: poisoning training data.\nModel inversion/extraction: reconstructing training data or the model itself from its outputs.'},
{d:'d5', f:'VPC, Security Groups, Shield', b:'VPC: aísla recursos de IA en red privada virtual.\nSecurity Groups: controlan el tráfico de red permitido.\nShield: protege contra ataques DDoS.', f_en:'VPC, Security Groups, Shield', b_en:'VPC: isolates AI resources on a virtual private network.\nSecurity Groups: control allowed network traffic.\nShield: protects against DDoS attacks.'},
{d:'d5', f:'AWS Config vs CloudTrail vs CloudWatch', b:'Config: CÓMO está configurado y qué cambió (estado de recursos).\nCloudTrail: QUIÉN hizo QUÉ (auditoría de llamadas a la API).\nCloudWatch: CÓMO se está desempeñando (métricas y logs).', f_en:'AWS Config vs CloudTrail vs CloudWatch', b_en:'Config: HOW it\'s configured and what changed (resource state).\nCloudTrail: WHO did WHAT (API call auditing).\nCloudWatch: HOW it\'s performing (metrics and logs).'},
{d:'d5', f:'Amazon Inspector, Audit Manager, Artifact', b:'Inspector: escanea vulnerabilidades en código/infraestructura automáticamente.\nAudit Manager: automatiza evidencia de auditoría para cumplimiento (GDPR, HIPAA, ISO 27001).\nArtifact: repositorio de informes de cumplimiento y certificaciones de AWS.', f_en:'Amazon Inspector, Audit Manager, Artifact', b_en:'Inspector: automatically scans code/infrastructure for vulnerabilities.\nAudit Manager: automates audit evidence for compliance (GDPR, HIPAA, ISO 27001).\nArtifact: repository of AWS compliance reports and certifications.'},
{d:'d5', f:'AWS Trusted Advisor', b:'Analiza tu cuenta y da recomendaciones en 5 áreas: seguridad, rendimiento, costo, tolerancia a fallos y límites de servicio.', f_en:'AWS Trusted Advisor', b_en:'Analyzes your account and gives recommendations in 5 areas: security, performance, cost, fault tolerance, and service limits.'},
{d:'d5', f:'Generative AI Security Scoping Matrix', b:'Marco de AWS que califica las apps de IA generativa por nivel de riesgo, según quién interactúa con el modelo y qué datos procesa.', f_en:'Generative AI Security Scoping Matrix', b_en:'AWS\'s framework that rates generative AI apps by risk level, based on who interacts with the model and what data it processes.'},
{d:'d5', f:'Políticas de ciclo de vida de S3', b:'Automatizan el ciclo completo de los datos: transición entre clases de almacenamiento, expiración, etc. Clave para la gobernanza de datos.', f_en:'S3 lifecycle policies', b_en:'Automate the full data lifecycle: transitions between storage classes, expiration, etc. Key for data governance.'},
{d:'d5', f:'Amazon Bedrock AgentCore Identity y Policy', b:'AgentCore Identity: gestiona la identidad y autenticación de cada agente (quién es, qué credenciales usa).\nPolicy en AgentCore: define qué puede hacer un agente y a qué herramientas/recursos puede acceder — control de acceso granular para agentes autónomos.', f_en:'Amazon Bedrock AgentCore Identity and Policy', b_en:'AgentCore Identity: manages each agent\'s identity and authentication (who it is, what credentials it uses).\nPolicy in AgentCore: defines what an agent can do and which tools/resources it can access — granular access control for autonomous agents.'},
{d:'d5', f:'Detección de alucinaciones y "grounding"', b:'Técnicas para mejorar la exactitud de las salidas: RAG grounding (anclar respuestas a fuentes recuperadas verificables), output validation (validar la salida antes de mostrarla), confidence scoring (medir qué tan segura está la respuesta del modelo).', f_en:'Hallucination detection and "grounding"', b_en:'Techniques to improve output accuracy: RAG grounding (anchoring answers to verifiable retrieved sources), output validation (validating output before showing it), confidence scoring (measuring how confident the model\'s answer is).'},
{d:'d5', f:'Toxicidad y filtrado de salida', b:'Detectar y bloquear contenido tóxico, dañino o inapropiado en las respuestas del modelo antes de que lleguen al usuario final — parte de las consideraciones de seguridad y privacidad en producción.', f_en:'Toxicity and output filtering', b_en:'Detecting and blocking toxic, harmful, or inappropriate content in the model\'s responses before it reaches the end user — part of security and privacy considerations in production.'},
{d:'d5', f:'Auditoría y logging de interacciones de IA', b:'Registrar de forma sistemática las interacciones con sistemas de IA (prompts, respuestas, decisiones del agente) para trazabilidad, cumplimiento y detección de mal uso — se apoya en CloudTrail/CloudWatch.', f_en:'Auditing and logging AI interactions', b_en:'Systematically recording interactions with AI systems (prompts, responses, agent decisions) for traceability, compliance, and misuse detection — relies on CloudTrail/CloudWatch.'},
{d:'d5', f:'Data residency / retention / lifecycle', b:'Residency: los datos solo se almacenan/procesan en una ubicación GEOGRÁFICA concreta. Retention: cuánto tiempo se guardan y cuándo se borran. Lifecycle management: reglas de todo el ciclo (creación → archivado → eliminación).', f_en:'Data residency / retention / lifecycle', b_en:'Residency: data is stored/processed only in a specific GEOGRAPHIC location. Retention: how long it\'s kept and when it\'s deleted. Lifecycle management: rules for the whole cycle (creation → archival → deletion).'},
{d:'d5', f:'Monitoreo de datos vs logging', b:'Monitoreo/observación: vigilancia CONTINUA de cómo se accede y usa los datos (detecta patrones no autorizados). Logging: registra eventos individuales. Para guardar logs años al menor costo → S3 Intelligent-Tiering.', f_en:'Data monitoring vs logging', b_en:'Monitoring/observation: CONTINUOUS watching of how data is accessed and used (detects unauthorized patterns). Logging: records individual events. To keep logs for years at the lowest cost → S3 Intelligent-Tiering.'},
{d:'d5', f:'Bedrock model invocation logging vs CloudTrail', b:'Invocation logging: registra los PROMPTS y RESPUESTAS del modelo (el contenido). CloudTrail: registra solo la LLAMADA a la API (quién, qué acción, cuándo), no el contenido.', f_en:'Bedrock model invocation logging vs CloudTrail', b_en:'Invocation logging: records the model\'s PROMPTS and RESPONSES (the content). CloudTrail: logs only the API CALL (who, what action, when), not the content.'},
{d:'d5', f:'SageMaker network isolation', b:'Ejecuta entrenamientos e inferencias SIN acceso a internet — la respuesta para entornos regulados que exigen un ambiente sellado. Para tráfico privado hacia servicios AWS → PrivateLink / VPC endpoints.', f_en:'SageMaker network isolation', b_en:'Runs training and inference WITHOUT internet access — the answer for regulated environments that require a sealed environment. For private traffic to AWS services → PrivateLink / VPC endpoints.'},
{d:'d5', f:'Leyes de accountability algorítmico', b:'Regulan las decisiones AUTOMATIZADAS sobre personas (crédito, contratación, scoring). Si la empresa expande a un nuevo mercado con decisiones automatizadas → revisar estas leyes locales.', f_en:'Algorithm accountability laws', b_en:'Regulate AUTOMATED decisions about people (credit, hiring, scoring). If the company expands into a new market with automated decisions → review these local laws.'},
];
